import machine
import time
import network
from umqtt.simple import MQTTClient

# Wi-Fi credentials
WIFI_SSID = "YOUR_WIFI_SSID"
WIFI_PASSWORD = "YOUR_WIFI_PASSWORD"

# MQTT broker details
MQTT_BROKER_IP = "YOUR_MQTT_BROKER_IP"
MQTT_CLIENT_ID = "esp32_temp_sensor"
MQTT_TOPIC_TEMP = "sensors/temp"

# Sensor simulation (replace with actual sensor reading)
def read_temperature():
    # Simulate reading a temperature sensor (e.g., from a DHT11/22 or DS18B20)
    # For demonstration, returning a dummy value
    return 25.0 + (time.ticks_ms() % 10000 / 10000 * 5) # Simulate some variation

def connect_wifi():
    print("Connecting to WiFi...")
    sta_if = network.WLAN(network.STA_IF)
    sta_if.active(True)
    sta_if.connect(WIFI_SSID, WIFI_PASSWORD)
    while not sta_if.isconnected():
        time.sleep(1)
        print(".", end="")
    print("\nWiFi connected:", sta_if.ifconfig())

def main():
    connect_wifi()

    client = MQTTClient(MQTT_CLIENT_ID, MQTT_BROKER_IP)
    try:
        client.connect()
        print(f"Connected to MQTT broker: {MQTT_BROKER_IP}")
    except Exception as e:
        print(f"Could not connect to MQTT broker: {e}")
        machine.reset() # Reset if connection fails

    while True:
        try:
            temperature = read_temperature()
            msg = f"{temperature:.2f}"
            client.publish(MQTT_TOPIC_TEMP, msg)
            print(f"Published temperature: {msg}°C to topic: {MQTT_TOPIC_TEMP}")
        except OSError as e:
            print(f"Failed to publish message: {e}")
            print("Reconnecting to MQTT...")
            try:
                client.connect()
                print("Reconnected to MQTT broker.")
            except Exception as e_reconnect:
                print(f"Failed to reconnect to MQTT broker: {e_reconnect}")
                machine.reset() # Reset if reconnection fails
        except Exception as e:
            print(f"An unexpected error occurred: {e}")
            machine.reset() # Reset for other critical errors

        time.sleep(5) # Publish every 5 seconds

if __name__ == "__main__":
    main()